def compute(inputs):
    beginning_value = inputs.get('beginning_value')
    ending_value = inputs.get('ending_value')
    num_years = inputs.get('num_years')
    cagr = (ending_value / beginning_value) ** (1 / num_years) - 1
    return {"cagr": cagr}

